export const JOB_POST_FEE_WEI = BigInt("10000000000000");

export function getContractAddress(): `0x${string}` | null {
  if (typeof window !== "undefined") {
    const addr = localStorage.getItem("gigdrop_contract_address");
    return addr as `0x${string}` | null;
  }
  return null;
}

export function setContractAddress(address: `0x${string}`) {
  localStorage.setItem("gigdrop_contract_address", address);
}

export function encodeJobId(jobId: string): `0x${string}` {
  const enc = new TextEncoder();
  const bytes = enc.encode(jobId).slice(0, 32);
  const hex = Array.from(bytes)
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("");
  return ("0x" + hex.padEnd(64, "0")) as `0x${string}`;
}
